"import os
import json

brain_dir = r"C:\Users\Pablo Villegas\.gemini\antigravity-ide\brain"
sessions = []

for folder in os.listdir(brain_dir):
    folder_path = os.path.join(brain_dir, folder)
    if not os.path.isdir(folder_path) or folder == "tempmediaStorage":
        continue

    transcript_path = os.path.join(folder_path, ".system_generated", "logs", "transcript.jsonl")
    first_request = "No initial request found"
    date_str = "Unknown Date"

    if os.path.exists(transcript_path):
        try:
            with open(transcript_path, 'r', encoding='utf-8') as f:
                for line in f:
                    data = json.loads(line)
                    if data.get("type") == "USER_INPUT":
                        content = data.get("content", "")
                        # Try to extract <USER_REQUEST>...</USER_REQUEST>
                        if "<USER_REQUEST>" in content:
                            start = content.find("<USER_REQUEST>") + len("<USER_REQUEST>")
                            end = content.find("</USER_REQUEST>")
                            first_request = content[start:end].strip()
                        else:
                            first_request = content.strip()

                        created_at = data.get("created_at", "")
                        if created_at:
                            date_str = created_at
                        break
        except Exception as e:
            first_request = f"Error reading transcript: {e}"

    sessions.append({
        "id": folder,
        "date": date_str,
        "first_request": first_request[:100] + "..." if len(first_request) > 100 else first_request
    })

# Print findings
print(json.dumps(sessions, indent=2, ensure_ascii=False))
"

